class Solution {
    public int maxValue(int n, int index, int maxSum) {
        int left = index, right = index;
        while (left > 0 || right < n - 1) {
            int sum = 0;
            int i = left;
            while (i >= 0 && sum + 2 + (i + 1) <= maxSum) {
                sum += 2 + (i + 1);
                --i;
            }
            int j = right;
            while (j < n - 1 && sum + 2 + (n - 1 - j) <= maxSum) {
                sum += 2 + (n - 1 - j);
                ++j;
            }
            if (sum > maxSum) break;
            left = i;
            right = j;
        }
        return left + 1;
    }
}
